// ═══════════════════════════════════════════════════
// Newton v2: 提取正文 + 构建多模态复用请求
// ═══════════════════════════════════════════════════

const response = $input.first().json;
const prev = $('📝 Newton v2 Prompt (黑话注入)').first().json;

const article = response.choices?.[0]?.message?.content || '';

// 提取文章标题
const firstLine = article.split('\n').find(l => l.trim() && !l.startsWith('```')) || '';
const title = firstLine.replace(/^#+\s*/, '').substring(0, 80);

return {
  _newton_draft: article,
  _newton_title: title,
  _newton_tokens: response.usage || {},
  _owl_source_url: prev._owl_source_url,
  _owl_raw_body: prev._owl_raw_body,
  // 同时传给下一个 DeepSeek 节点做多模态复用
  _repurpose_prompt: `你是一个**内容运营专家**。请将下面的文章拆解为适配不同平台的版本。

原文标题: ${title}

原文内容:
${article.substring(0, 3000)}

### 📕 小红书图文 (活泼、emoji密集、每句换行、带标签)
【标题】15字以内爆款标题
【正文】3-5个核心要点
【互动引导】引导评论
【标签】5-8个话题标签

### 🎵 短视频脚本 (口语化、快节奏、适合口播)
【黄金3秒】震撼开场
【核心内容】3个要点（标注[画面切换]）
【结尾CTA】引导点赞收藏

### ⚡ 要点速览 (极简、适合截图转发)
【一句话总结】20字
【3个关键数字】
【1个行动建议】

---
不打乱原文、不编造数据。用 --- 分割各平台内容。`
};

// ═══════════════════════════════════════════════════
// 构建多模态内容请求
// ═══════════════════════════════════════════════════

const data = $input.first().json;

return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 2048,
  messages: [
    { role: 'user', content: data._repurpose_prompt }
  ],
  _newton_draft: data._newton_draft,
  _newton_title: data._newton_title
};

// ═══════════════════════════════════════════════════
// 合并正文 + 多模态内容 → 最终输出
// ═══════════════════════════════════════════════════

const dsResponse = $input.first().json;
const prev = $('🔄 构建复用 Prompt').first().json;

const multimodal = dsResponse.choices?.[0]?.message?.content || '';
const article = prev._newton_draft || '';

// 拼接: 正文 + 分割线 + 多模态复用内容
const finalContent = article + '\n\n---\n\n' + multimodal;

return {
  // 最终输出（给 Sherlock + Midas）
  _newton_draft: finalContent,
  _newton_title: prev._newton_title,
  _newton_tokens: prev._newton_tokens,
  _has_multimodal: multimodal.length > 50
};
